function app(){
    let option1, option2, option3;

    function getGreenThumb(sun, water, pet) {
        return fetch("https://front-br-challenges.web.app/api/v2/green-thumb/?sun=" + sun + "&water=" + water + "&pets=" + pet)
        .then(function(response) {
            return response.json();
        });
    }

    function createItem(id, name, sun, water, url, price, toxicity, staff_favorite) {
        let item = document.createElement("div");
        item.setAttribute("id", id);
        item.setAttribute("class", "item");
        
        if (staff_favorite) {
            item.setAttribute("class", "item staff_favorite");
            // star
            let star = document.createElement("img")
            star.setAttribute("class", "img");
            star.setAttribute("src", url);
        
            // green brand staff
            let itemStaff = document.createElement("div");
            itemStaff.setAttribute("class", "staff_favorite");
            itemStaff.innerHTML = "✨Staff favorite";


            item.appendChild(itemStaff);
        }
        
        let image = document.createElement("img")
        image.setAttribute("class", "img");
        image.setAttribute("src", url);

        let itemName = document.createElement("div")
        itemName.setAttribute("class", "name");
        itemName.innerHTML = name;

        let itemInfo = document.createElement("div")
        itemInfo.setAttribute("class", "info");

        let itemPrice = document.createElement("div")
        itemPrice.setAttribute("class", "price");
        itemPrice.innerHTML = "$" + price;
        itemInfo.appendChild(itemPrice);
        
        let details = document.createElement("div")
        details.setAttribute("class", "details");
        itemInfo.appendChild(details);
        
        // draw pet icon
        if (toxicity) {
            let itemToxicity = cloneIcon("toxic");
            details.appendChild(itemToxicity);
        }
       // draw pet icon
        if (option3 === "true") {
            let itemPet = cloneIcon("pet");
            details.appendChild(itemPet);
        }

        // draw sun icon
        let itemSun;
        if (option1 === "no") {
            itemSun = cloneIcon("no-sun");
        } else if (option1 === "low") {
            itemSun = cloneIcon("low-sun");
        } else if (option1 === "high") {
            itemSun = cloneIcon("high-sun");
        }
        details.appendChild(itemSun);
        
        // draw sun icon
        let itemWater;
        if (option2 === "rarely") {
            itemWater = cloneIcon("drop-1");
        } else if (option2 === "regularly") {
            itemWater = cloneIcon("drop-2");
        } else if (option2 === "daily") {
            itemWater = cloneIcon("drop-3");
        }
        
        details.appendChild(itemWater);
        


        item.appendChild(image);
        item.appendChild(itemName);
        item.appendChild(itemInfo);

        return item;
    }

    function getResultstext() {
        return document.querySelectorAll("div.products > .no-result-container");
    }
    
    function cloneIcon(iconName) {
        return document.querySelector("div.pre-load > img." + iconName).cloneNode();
    }

    function showTextResults() {
        getResultstext().forEach(noResult=> {
            noResult.style.display="flex";
        });
    }
    function hideTextResults() {
        getResultstext().forEach(noResult=> {
            noResult.style.display="none";
        });
    }
    
    function getLoader() {
        return document.querySelector("div.products > .loader");
    }
    function showLoader() {
        getLoader().style.display = "flex";
    }

    function hideLoader() {
        getLoader().style.display = "none";
    }

    function getItems() {
        return document.querySelector("div.products > .items");
    }
    function showItems() {
        getItems().style.display = "contents";
    }

    function hideItems() {
        getItems().style.display = "none";
    }


    function scrollToUp(){
        window.scrollTo({ top: 0, behavior: 'smooth' });
    }
    
    function scrollToDown(){
        window.scrollTo({ top: window.screen.height, behavior: 'smooth' });
    }

    // listenner go to top page
    document.getElementById("go-up").onclick = function() {scrollToUp()};

    var selectors = document.getElementsByName("selector");
    selectors.forEach(selector=> {
        selector.addEventListener("change", function() {
            switch(selector.id) {
                case "option-1":
                    option1 = selector.value;
                    break;
                case "option-2":
                    option2 = selector.value;
                    break;
                case "option-3":
                    option3 = selector.value;
                    break;
            }
            
            if (option1 && option2 && option3) {
                let itemsOutput = document.getElementsByClassName("items-output")[0];
                
                showLoader();
                scrollToDown();
                hideTextResults();
                hideItems();

                while (itemsOutput.firstChild) {
                    itemsOutput.firstChild.remove()
                }
                
                setTimeout(() => {
                    
                getGreenThumb(option1, option2, option3).then(items => {
                    // sort to staff true
                    items.sort((a,b) => a.staff_favorite ? -1 : 1);

                    items.forEach(item=> {
                        itemsOutput.appendChild(createItem(item.id, item.name, item.sun, item.water, item.url, item.price, item.toxicity, item.staff_favorite));
                    });
                    
                    hideLoader();
                    hideTextResults();
                    showItems();
                    scrollToDown();
                    
                }).catch(e=> {
                    // some request gime us 404.. not found..
                    scrollToUp();
                    showTextResults();
                    hideLoader();
                    hideItems();

                })
                
            }, 0);
            }

        });
    });
    

    
}

// call application when document is complete
var loaderInvterval = setInterval(()=>{
    if (document.readyState === "complete") {
        clearInterval(loaderInvterval);
        app();
    }
},100);
